import{c as a,Q as n,j as t,m as i}from"./chunks/framework.CBiVa4O3.js";const g=JSON.parse('{"title":"为什么要 VM","description":"","frontmatter":{},"headers":[],"relativePath":"../interpreterLearning/20-为什么要VM.md","filePath":"../interpreterLearning/20-为什么要VM.md","lastUpdated":1778496697000}'),e={name:"../interpreterLearning/20-为什么要VM.md"};function p(o,s,l,h,r,d){return n(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="为什么要-vm" tabindex="-1">为什么要 VM <a class="header-anchor" href="#为什么要-vm" aria-label="Permalink to &quot;为什么要 VM&quot;">​</a></h1><p>Mochi 跑得通了——但你跑一遍 <code>fib(30)</code> 要等 5 秒,<code>fib(35)</code> 已经够倒一杯咖啡。问题不在算法,在执行引擎:<strong>树遍历解释器每访问一个 AST 节点都要 dispatch、查类型、new 一个临时 Value 对象</strong>,内存散落在堆里,L1 缓存命中率低到可怜。CPython 走过这条路、V8 早期也走过这条路——<strong>最终都换成了字节码 VM</strong>,加速一个数量级起步。这一篇讲清楚为什么要重写后端,以及为什么 Mochi 只做单层栈式 VM 就够。</p><blockquote><p>一句话先记住:<strong>树遍历是&quot;语义解释器&quot;,字节码是&quot;指令解释器&quot;</strong>——前者方便改语义,后者方便跑得快。等语义稳定了,就该把它编译成一串紧凑的字节码,让 CPU 缓存帮我们做事。</p></blockquote><hr><h2 id="一、树遍历到底慢在哪" tabindex="-1">一、树遍历到底慢在哪 <a class="header-anchor" href="#一、树遍历到底慢在哪" aria-label="Permalink to &quot;一、树遍历到底慢在哪&quot;">​</a></h2><p>回顾一下 Mochi 当前的 evaluator(11 篇写的):</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> evaluate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">node</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Node</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">env</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Env</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  switch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (node.type) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    case</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;NumberLit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> node.value;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    case</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;BinaryOp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">      const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> evaluate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(node.left, env);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">      const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> r</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> evaluate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(node.right, env);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">      return</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> applyOp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(node.op, l, r);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // ... 30 个 case</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>跑 <code>1 + 2 * 3</code> 时实际发生的事:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>evaluate(BinaryOp +)</span></span>
<span class="line"><span>  ├─ evaluate(NumberLit 1)        函数调用 + switch dispatch + 装箱</span></span>
<span class="line"><span>  ├─ evaluate(BinaryOp *)         函数调用 + switch dispatch</span></span>
<span class="line"><span>  │     ├─ evaluate(NumberLit 2)  函数调用 + switch + 装箱</span></span>
<span class="line"><span>  │     ├─ evaluate(NumberLit 3)  函数调用 + switch + 装箱</span></span>
<span class="line"><span>  │     └─ applyOp                拆箱 + 加法 + 装箱</span></span>
<span class="line"><span>  └─ applyOp                      拆箱 + 加法 + 装箱</span></span></code></pre></div><p><strong>算一个 <code>1 + 2 * 3</code> 做了 5 次函数调用、5 次 switch 分发、4 次装箱/拆箱</strong>。问题汇总:<strong>节点散落在堆上</strong>(AST 节点是 <code>new</code> 出来的 JS 对象,缓存未命中)、<strong>指针追逐</strong>(<code>node.left</code> 解引用 L1 miss 100+ cycles)、<strong>递归调用栈深</strong>(<code>fib(30)</code> 求值深度上千层)、<strong>泛型分发</strong>(<code>applyOp</code> 每次都走 if 链判断类型)、<strong>装箱开销</strong>(每个中间结果都是 <code>{tag, value}</code> 对象)。</p><hr><h2 id="二、实测-树遍历-vs-字节码的差距" tabindex="-1">二、实测:树遍历 vs 字节码的差距 <a class="header-anchor" href="#二、实测-树遍历-vs-字节码的差距" aria-label="Permalink to &quot;二、实测:树遍历 vs 字节码的差距&quot;">​</a></h2><div class="language-mochi vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mochi</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fn fib(n) { if (n &lt; 2) { return n } return fib(n - 1) + fib(n - 2) }</span></span>
<span class="line"><span>print(fib(30))</span></span></code></pre></div><table tabindex="0"><thead><tr><th>实现</th><th>耗时 (fib(30))</th><th>比例</th></tr></thead><tbody><tr><td>Mochi 树遍历(当前)</td><td>~5000 ms</td><td>1×</td></tr><tr><td>Mochi 字节码 VM(目标)</td><td>~500 ms</td><td>10×</td></tr><tr><td>Node.js(V8 Ignition)</td><td>~15 ms</td><td>333×</td></tr><tr><td>手写 C</td><td>~3 ms</td><td>1666×</td></tr></tbody></table><p><strong>字节码版本的目标:比树遍历快 10 倍</strong>。再往上(V8 / native)的差距,靠 JIT 和原生编译——这是 28 篇之后的事,Mochi 不做。</p><hr><h2 id="三、为什么字节码快" tabindex="-1">三、为什么字节码快 <a class="header-anchor" href="#三、为什么字节码快" aria-label="Permalink to &quot;三、为什么字节码快&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>树遍历                                   字节码 VM</span></span>
<span class="line"><span>                                         ip = 0</span></span>
<span class="line"><span>function evaluate(node) {                while (true) {</span></span>
<span class="line"><span>  switch (node.type) {                     op = bytecode[ip++]</span></span>
<span class="line"><span>    case ADD:                              switch (op) {</span></span>
<span class="line"><span>      l = evaluate(left)                     case ADD:</span></span>
<span class="line"><span>      r = evaluate(right)                      r = stack.pop()</span></span>
<span class="line"><span>      return l + r                             l = stack.pop()</span></span>
<span class="line"><span>    ...                                        stack.push(l + r)</span></span>
<span class="line"><span>  }                                          ...</span></span>
<span class="line"><span>}                                          }</span></span>
<span class="line"><span>节点 = 散落对象,递归调用              }</span></span>
<span class="line"><span>                                         字节码 = 连续数组,大循环 + switch</span></span></code></pre></div><p>四个根本原因:</p><p><strong>3.1 内存紧凑</strong>:字节码是连续 <code>Uint8Array</code>——CPU 读完一条指令,下一条已经预取进 L1。AST 是堆里的对象,根本指望不上 prefetcher。</p><p><strong>3.2 指令分发便宜</strong>:一个大 <code>switch</code> 跳转,比一层层函数调用 + 节点 type 判断便宜得多。<strong>computed goto</strong>(GCC 扩展)能让分发再快 20-30%——CPython / Ruby 都用,Mochi 22 篇会讲。</p><p><strong>3.3 局部变量编号</strong>:树遍历查 <code>env</code> 哈希表(每次至少一次 hash + 字符串比较);字节码版变量在编译期就分配好<strong>槽位编号</strong>(slot 0、slot 1...),运行时是 <code>frame[3]</code> 这种<strong>数组下标访问</strong>——L1 命中,纳秒级。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>树遍历:   env.lookup(&quot;x&quot;)    哈希表查找       O(链长)</span></span>
<span class="line"><span>字节码:   frame[2]            数组下标         O(1) + cache friendly</span></span></code></pre></div><p><strong>3.4 常量预提取</strong>:<code>1 + 2 * 3</code> 里的 <code>1 / 2 / 3</code> 在编译期就被塞进常量池,字节码里只放 index。字面量在运行时不需要再&quot;造出来&quot;。</p><hr><h2 id="四、树遍历的好处-别全否定它" tabindex="-1">四、树遍历的好处:别全否定它 <a class="header-anchor" href="#四、树遍历的好处-别全否定它" aria-label="Permalink to &quot;四、树遍历的好处:别全否定它&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>树遍历</th><th>字节码</th></tr></thead><tbody><tr><td>实现复杂度</td><td>低(一个 evaluate 函数)</td><td>中(编译器 + VM 两块)</td></tr><tr><td>改语义</td><td>改一处</td><td>改三处(parser / compiler / VM)</td></tr><tr><td>启动时间</td><td>0(直接跑 AST)</td><td>要先编译</td></tr><tr><td>debug 体验</td><td>行号直接是 AST 节点</td><td>需要 source map 反查</td></tr><tr><td>适合阶段</td><td><strong>原型期</strong></td><td><strong>稳定期</strong></td></tr></tbody></table><p><strong>前 15 篇写树遍历不是浪费</strong>——是先把语义试通,确认语言长什么样了再上 VM。工业级也有不少树遍历的&quot;短命语言&quot;:Bash 是树遍历(脚本一次性跑完,启动时间敏感)、SQLite 早期是树遍历、很多 DSL 都是树遍历。</p><hr><h2 id="五、什么时候该重写" tabindex="-1">五、什么时候该重写 <a class="header-anchor" href="#五、什么时候该重写" aria-label="Permalink to &quot;五、什么时候该重写&quot;">​</a></h2><p>经验法则,满足任何一条就该上 VM:</p><ol><li>用户开始抱怨&quot;为什么我这段代码这么慢&quot;——性能成为瓶颈</li><li>语言核心特性已经稳定(类、模块、闭包都齐了)</li><li>准备做 hot loop 优化 / JIT 的前提</li><li>想做时间旅行 debugger / 录制重放——字节码比 AST 容易序列化</li></ol><p><strong>Mochi 已经满足 1 和 2,可以重写了</strong>。</p><hr><h2 id="六、整体重写-vs-增量" tabindex="-1">六、整体重写 vs 增量 <a class="header-anchor" href="#六、整体重写-vs-增量" aria-label="Permalink to &quot;六、整体重写 vs 增量&quot;">​</a></h2><p><strong>A. 双引擎并存</strong>:树遍历不动,加 <code>--bytecode</code> flag 切到 VM。 <strong>B. 整体替换</strong>:删掉 evaluator.ts,所有路径都走 VM。</p><p><strong>推荐 B,但保留树遍历做 REPL 调试模式</strong>——REPL 里改一个变量定义就要重新编译整个文件实在痛苦,树遍历直接 eval 是 REPL 的最佳形态(Python / Node REPL 都是某种意义上的&quot;半树遍历&quot;)。理由:双引擎并存,<strong>任何语义改动要改两处</strong>——闭包、类、异常的语义一旦在两个引擎之间漂移,debug 痛得想哭。完整重写一遍<strong>逼你把语义画清楚</strong>,字节码就是&quot;语义的可执行形式&quot;。</p><hr><h2 id="七、工业级走过的同一条路" tabindex="-1">七、工业级走过的同一条路 <a class="header-anchor" href="#七、工业级走过的同一条路" aria-label="Permalink to &quot;七、工业级走过的同一条路&quot;">​</a></h2><p><strong>CPython:树遍历 → 字节码(很早)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.py 源码 → parser → AST → compile.c → .pyc 字节码 → ceval.c 大循环</span></span></code></pre></div><p>CPython 没有真正的&quot;树遍历时期&quot;(0.9 时代很短),现在所有 <code>python xxx.py</code> 都先编译成字节码再跑。<code>.pyc</code> 文件就是缓存的字节码。CPython 3.11 起还有 specializing interpreter(把高频 opcode 替换成专门版本),3.13 开始有自适应解释器——baseline JIT 的雏形。</p><p><strong>V8:树遍历 → Crankshaft → Ignition</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2008 V8 初版   :不走解释器,直接 JIT(Full-codegen)</span></span>
<span class="line"><span>2010 Crankshaft:加优化 JIT</span></span>
<span class="line"><span>2017 Ignition  :加回字节码解释器(因为内存吃太多)+ TurboFan 做优化 JIT</span></span></code></pre></div><p><strong>V8 是反过来的</strong>:一开始嫌字节码慢,直接生成机器码;后来发现内存吃不消,<strong>才&quot;退回去&quot;加了字节码解释器</strong>。</p><p>JVM、Lua、Ruby、PHP——<strong>所有跑得快的动态语言,核心都是字节码 VM</strong>。</p><hr><h2 id="八、mochi-的执行链路对比" tabindex="-1">八、Mochi 的执行链路对比 <a class="header-anchor" href="#八、mochi-的执行链路对比" aria-label="Permalink to &quot;八、Mochi 的执行链路对比&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>重写前(15 篇结束):                重写后(25 篇结束):</span></span>
<span class="line"><span>  Mochi 源码 → tokens → AST           Mochi 源码 → tokens → AST</span></span>
<span class="line"><span>    → evaluate(AST, env)  ← 慢          → compile(AST)       ← 24 篇</span></span>
<span class="line"><span>    → Value                             → bytecode + 常量池</span></span>
<span class="line"><span>                                        → VM dispatch loop   ← 22 篇</span></span>
<span class="line"><span>                                        → Value</span></span></code></pre></div><p>工业级再往上就是 <code>bytecode → profiler 发现 hot loop → optimizing JIT(TurboFan / HotSpot C2)→ 机器码 → CPU 直接跑</code>——<strong>Mochi 不做最后两层</strong>,加 JIT 是 28 篇的话题,只讲心智不实现。</p><hr><h2 id="九、mochi-这里偷懒了" tabindex="-1">九、Mochi 这里偷懒了 <a class="header-anchor" href="#九、mochi-这里偷懒了" aria-label="Permalink to &quot;九、Mochi 这里偷懒了&quot;">​</a></h2><ul><li><strong>不做双层执行(baseline + optimizing)</strong>——V8 那种 Ignition + TurboFan 双层 Mochi 不做,只做一层字节码 VM</li><li><strong>不做 inline cache</strong>——<code>x.foo</code> 的方法分派每次都走完整查找,<strong>这是 Mochi VM 性能的最大留白</strong></li><li><strong>不做 superinstruction</strong>——CPython 3.11 引入的高频组合(<code>LOAD_FAST</code> + <code>LOAD_FAST</code> → <code>LOAD_FAST_LOAD_FAST</code>)Mochi 不做</li><li><strong>不做寄存器式</strong>——23 篇讲完寄存器式 VM 的取舍,但 Mochi 主线选栈式(实现简单、编译器简单)</li><li><strong>不做 .mocp 字节码缓存</strong>——Python 的 <code>.pyc</code> Mochi 没有,每次启动都重新编译</li></ul><hr><p>下一篇:<code>21-字节码设计.md</code>,把 Mochi VM 的&quot;虚拟 ISA&quot;定死——15 条左右的 opcode、常量池结构、跳转编码、反汇编工具。<strong>字节码格式一旦定下来后面 22-25 都在这上面叠,所以必须严谨</strong>。</p>`,55)])])}const k=a(e,[["render",p]]);export{g as __pageData,k as default};
